import { type Ref, type RefCallback, type RefObject, useCallback, useRef } from 'react';

type OptionalRef<T> = Ref<T> | undefined;

type Cleanup = (() => void) | undefined | void;

type MultiRef<T> = RefCallback<T> &
  RefObject<T | null> & {
    ref: RefObject<T | null>;
  };

export function setRef<T>(ref: OptionalRef<T>, value: T): Cleanup {
  if (typeof ref === 'function') {
    const cleanup = ref(value);

    if (typeof cleanup === 'function') {
      return cleanup;
    }
    return () => ref(null);
  } else if (ref) {
    ref.current = value;
    return () => (ref.current = null);
  }
}

export function useCombinedRefs<T>(...refs: OptionalRef<T>[]) {
  const ref = useRef<T | null>(null);

  const refFn = useCallback<RefCallback<T>>(value => {
    ref.current = value;
    const cleanups: Cleanup[] = [];

    for (const ref of refs) {
      const cleanup = setRef(ref, value);
      if (typeof cleanup === 'function') cleanups.push(cleanup);
    }

    if (!cleanups.length) return;

    return () => {
      ref.current = null;
      for (const cleanup of cleanups) {
        cleanup?.();
      }
    };
    // biome-ignore lint/correctness/useExhaustiveDependencies: The hook already lists all dependencies
  }, refs) as MultiRef<T>;

  if (!Object.getOwnPropertyDescriptor(refFn, 'current'))
    Object.defineProperty(refFn, 'current', {
      get() {
        return ref.current;
      },
    });

  if (!Object.getOwnPropertyDescriptor(refFn, 'ref'))
    Object.defineProperty(refFn, 'ref', {
      get() {
        return ref;
      },
    });

  return refFn;
}
